188	// ProfileLadders contains an entry for profile, that wins. Otherwise falls
189	// back to the deprecated ProfilePriority for the default profile only. If
190	// neither is set, returns the shipped FEAT-006 profile ladder.
191	func (r *RoutingConfig) ResolvedLadder(profile string) []string {
192		if profile == "" {
193			profile = "default"
194		}
195		if r == nil {
196			if ladder, ok := defaultProfileLadders[profile]; ok {
197				return append([]string(nil), ladder...)
198			}
199			return append([]string(nil), defaultProfileLadders["default"]...)
200		}
201		if r.ProfileLadders != nil {
202			if ladder, ok := r.ProfileLadders[profile]; ok && len(ladder) > 0 {
203				return append([]string(nil), ladder...)
204			}
205		}
206		if profile == "default" && len(r.ProfilePriority) > 0 {
207			return append([]string(nil), r.ProfilePriority...)
208		}
209		if ladder, ok := defaultProfileLadders[profile]; ok {
210			return append([]string(nil), ladder...)
211		}
212		return append([]string(nil), defaultProfileLadders["default"]...)
213	}
